class TrieNode:
    def __init__(self):
        self.children = [None]*26
        self.is_end = False

class Solution:
    def deleteWord(self, root, word):
        if not word:
            return True

        index = ord(word[0]) - ord('a')
        if root.children[index] is None:
            return False

        if self.deleteWord(root.children[index], word[1:]):
            root.children[index].is_end = False
            root.children[index] = None

        return True

def solve():
    root = TrieNode()
    for word in ['apple', 'banana', 'banana', 'banana']: root.insert(word)
    print(Solution().deleteWord(root, 'banana'))

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for ch in word:
            index = ord(ch) - ord('a')
            if node.children[index] is None:
                node.children[index] = TrieNode()
            node = node.children[index]
        node.is_end = True

if __name__ == '__main__':
    solve()

