class TrieNode {
    public:
        TrieNode* children[26];
        bool isEnd;
        TrieNode() {
            for (int i = 0; i < 26; i++)
                children[i] = nullptr;
            isEnd = false;
        }
    };

class Trie {
public:
    TrieNode* root;

    Trie() {
        root = new TrieNode();
    }

    void insert(const string &word) {
        TrieNode* node = root;
        for (char ch : word)
            node = node->children[ch - 'a'];
        node->isEnd = true;
    }

    void deleteWord(TrieNode* root, const string &word) {
        if (word.empty())
            return;

        int index = word[0] - 'a';
        if (root->children[index] == nullptr)
            return;

        if (deleteWord(root->children[index], word.substr(1)))
            root->children[index]->isEnd = false;
            root->children[index] = nullptr;

        return;
    }
}

int main() {
    Trie trie;
    for (const string &word : {'apple', 'banana', 'banana', 'banana'})
        trie.insert(word);
    trie.deleteWord(trie.root, 'banana');
    return 0;
}
